1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_PREMIUM = 25;
4	const BLOCK_SIZE = 3;
5	const BLOCK_PREMIUM = 60;
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_THRESHOLD_YEARS = 2;
11	const FOLLOWUP_DISCOUNT_RATE = 0.15;
12	const mainItemPremiums: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40 };
13	const componentTypes = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type Customer = { yearsWithMHPCO: number; contractNumber: number };
17	
18	const isComponent = (item: Item): boolean => componentTypes.has(item.type);
19	
20	const componentBasePremium = (components: Item[]): number => {
21	  const counts: Record<string, number> = {};
22	  for (const item of components) {
23	    counts[item.type] = (counts[item.type] ?? 0) + 1;
24	  }
25	  return Object.values(counts).reduce(
26	    (sum, count) => sum + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
27	    0,
28	  );
29	};
30	
31	const mainItemBasePremium = (items: Item[]): number =>
32	  items.reduce((sum, item) => sum + (mainItemPremiums[item.type] ?? 0), 0);
33	
34	const surchargeFor = (items: Item[], predicate: (item: Item) => boolean, rate: number): number =>
